     2|import { supabase } from '@/lib/supabase';
     3|import type { Session } from '@supabase/supabase-js';
     4|
     5|const KEYS = {
     6|  ACCESS_TOKEN: 'ivx_owner_resilient_access_token',
     7|  REFRESH_TOKEN: 'ivx_owner_resilient_refresh_token',
     8|  EMAIL: 'ivx_owner_resilient_email',
     9|  USER_ID: 'ivx_owner_resilient_user_id',
    10|  EXPIRES_AT: 'ivx_owner_resilient_expires_at',
    11|} as const;
    12|
    13|export type ResilientOwnerSession = {
    14|  accessToken: string;
    15|  refreshToken: string;
    16|  email: string;
    17|  userId: string;
    18|  expiresAt: number;
    19|};
    20|
    21|/**
    22| * Persist a copy of the owner Supabase session in SecureStore. This is the
    23| * resilience fallback for the rare React Native / Expo Go path where
    24| * `supabase.auth.setSession()` stores the session in AsyncStorage but a
    25| * subsequent `supabase.auth.getSession()` returns null (AsyncStorage not
    26| * flushed, bundle reload, or storage key mismatch). The SecureStore copy is
    27| * small (< 2KB) and lets the senior-developer preflight restore the real
    28| * session without asking the owner to sign in again.
    29| *
    30| * Never stores the password or any server secrets.
    31| */
    32|export async function storeOwnerResilientSession(session: Session): Promise<void> {
    33|  try {
    34|    await Promise.all([
    35|      SecureStore.setItemAsync(KEYS.ACCESS_TOKEN, session.access_token),
    36|      SecureStore.setItemAsync(KEYS.REFRESH_TOKEN, session.refresh_token || ''),
    37|      SecureStore.setItemAsync(KEYS.USER_ID, session.user.id),
    38|      SecureStore.setItemAsync(KEYS.EMAIL, session.user.email ?? ''),
    39|      SecureStore.setItemAsync(KEYS.EXPIRES_AT, String(session.expires_at ?? 0)),
    40|    ]);
    41|  } catch (error) {
    42|    console.log('[OwnerSessionResilience] store failed:', error instanceof Error ? error.message : 'unknown');
    43|  }
    44|}
    45|
    46|/** Clear the resilient owner session copy. Called on sign-out and on stale-token restore failure. */
    47|export async function clearOwnerResilientSession(): Promise<void> {
    48|  try {
    49|    await Promise.all([
    50|      SecureStore.deleteItemAsync(KEYS.ACCESS_TOKEN),
    51|      SecureStore.deleteItemAsync(KEYS.REFRESH_TOKEN),
    52|      SecureStore.deleteItemAsync(KEYS.USER_ID),
    53|      SecureStore.deleteItemAsync(KEYS.EMAIL),
    54|      SecureStore.deleteItemAsync(KEYS.EXPIRES_AT),
    55|    ]);
    56|  } catch (error) {
    57|    console.log('[OwnerSessionResilience] clear failed:', error instanceof Error ? error.message : 'unknown');
    58|  }
    59|}
    60|
    61|/** Read the resilient owner session copy. Returns null when nothing is stored or read fails. */
    62|export async function loadOwnerResilientSession(): Promise<ResilientOwnerSession | null> {
    63|  try {
    64|    const [accessToken, refreshToken, email, userId, expiresAt] = await Promise.all([
    65|      SecureStore.getItemAsync(KEYS.ACCESS_TOKEN),
    66|      SecureStore.getItemAsync(KEYS.REFRESH_TOKEN),
    67|      SecureStore.getItemAsync(KEYS.EMAIL),
    68|      SecureStore.getItemAsync(KEYS.USER_ID),
    69|      SecureStore.getItemAsync(KEYS.EXPIRES_AT),
    70|    ]);
    71|    if (!accessToken || !refreshToken) return null;
    72|    return {
    73|      accessToken,
    74|      refreshToken,
    75|      email: email ?? '',
    76|      userId: userId ?? '',
    77|      expiresAt: Number(expiresAt ?? 0),
    78|    };
    79|  } catch (error) {
    80|    console.log('[OwnerSessionResilience] load failed:', error instanceof Error ? error.message : 'unknown');
    81|    return null;
    82|  }
    83|}
    84|
    85|/**
    86| * Restore the owner session into the live Supabase client from the resilient
    87| * SecureStore copy. If the stored tokens are rejected or stale, they are
    88| * cleared so the owner is prompted to sign in again.
    89| *
    90| * Returns whether a live session is present and the owner's email after the
    91| * restore attempt.
    92| */
    93|export async function restoreOwnerResilientSession(): Promise<{ sessionPresent: boolean; userEmail: string | null }> {
    94|  const resilient = await loadOwnerResilientSession();
    95|  if (!resilient) return { sessionPresent: false, userEmail: null };
    96|  try {
    97|    const { data, error } = await supabase.auth.setSession({
    98|      access_token: resilient.accessToken,
    99|      refresh_token: resilient.refreshToken,
   100|    });
   101|    if (error || !data.session) {
   102|      console.log('[OwnerSessionResilience] stored tokens rejected; clearing:', error?.message ?? 'no session');
   103|      await clearOwnerResilientSession();
   104|      return { sessionPresent: false, userEmail: null };
   105|    }
   106|    return { sessionPresent: true, userEmail: data.session.user?.email ?? resilient.email ?? null };
   107|  } catch (error) {
   108|    console.log('[OwnerSessionResilience] restore threw:', error instanceof Error ? error.message : 'unknown');
   109|    return { sessionPresent: false, userEmail: null };
   110|  }
   111|}

