"}{"filePath": "backend/services/ivx-owner-recovery-audit.ts", "content": "/**
 * IVX Owner Recovery Audit — append-only, tamper-evident log.
 *
 * Records every recovery request/verify/resolve action without storing the raw
 * recovery token. Instead it stores a SHA-256 hash of the token and the phone
 * number so the audit trail can prove what happened while keeping secrets safe.
 *
 * Storage: local JSONL file under backend/logs/audit/owner-recovery/YYYY-MM-DD.jsonl
 * plus an in-memory ring buffer for live status checks. No raw tokens are ever
 * written.
 */
import { createHash, randomBytes } from 'node:crypto';
import { appendFile, mkdir } from 'node:fs/promises';
import { dirname } from 'node:path';

export type OwnerRecoveryAuditAction =
  | 'request'
  | 'verify_attempt'
  | 'verify_success'
  | 'verify_fail'
  | 'resolve_token'
  | 'password_repair'
  | 'rate_limited'
  | 'blocked'
  | 'expired_cleanup';

export type OwnerRecoveryAuditRecord = {
  /** ISO timestamp when the event was recorded. */
  timestamp: string;
  /** Action that triggered the audit event. */
  action: OwnerRecoveryAuditAction;
  /** Normalized owner email (lowercase). */
  email: string;
  /** SHA-256 hash of the phone number (E.164). Never stores raw phone. */
  phoneHash: string;
  /** SHA-256 hash of the recovery token. Null when no token involved. */
  tokenHash: string | null;
  /** IP / device fingerprint from the request headers. */
  ip: string;
  /** User-agent or device hint when available. */
  device: string;
  /** Whether the action succeeded. */
  success: boolean;
  /** Expiration timestamp (ISO) if relevant. */
  expiresAt: string | null;
  /** When the recovery token was used (ISO). */
  usedAt: string | null;
  /** Who/what initiated the action: 'owner', 'operator', 'system'. */
  operator: 'owner' | 'operator' | 'system';
  /** Human-readable reason for the audit event. */
  reason: string;
  /** Count of attempts when relevant. */
  attemptCount?: number;
  /** Environment marker (no secrets). */
  backendVersion: string;
};

const BACKEND_VERSION = 'ivx-owner-recovery-audit-v1';
const AUDIT_DIR = 'backend/logs/audit/owner-recovery';

/** In-memory ring buffer for recent events (last 256). */
const recentEvents: OwnerRecoveryAuditRecord[] = [];
const MAX_RECENT = 256;

function hash(value: string): string {
  return createHash('sha256').update(value, 'utf8').digest('hex');
}

export function hashPhone(phone: string): string {
  return hash(normalizePhone(phone));
}

export function hashToken(token: string): string {
  return hash(token);
}

export function normalizePhone(input: string): string {
  const raw = (input || '').trim().replace(/\D/g, '');
  if (!raw) return '';
  if (raw.length === 10) return `+1${raw}`;
  if (raw.length === 11 && raw.startsWith('1')) return `+${raw}`;
  return `+${raw}`;
}

function todayFile(): string {
  const date = new Date().toISOString().slice(0, 10);
  return `${AUDIT_DIR}/${date}.jsonl`;
}

/** Append a recovery audit event. Never stores raw tokens or raw phone numbers. */
export async function appendRecoveryAudit(event: Omit<OwnerRecoveryAuditRecord, 'timestamp' | 'backendVersion'>): Promise<void> {
  const record: OwnerRecoveryAuditRecord = {
    ...event,
    timestamp: new Date().toISOString(),
    backendVersion: BACKEND_VERSION,
  };

  recentEvents.push(record);
  if (recentEvents.length > MAX_RECENT) {
    recentEvents.shift();
  }

  try {
    const path = todayFile();
    await mkdir(dirname(path), { recursive: true });
    await appendFile(path, `${JSON.stringify(record)}\n`, 'utf8');
  } catch (error) {
    console.log('[OwnerRecoveryAudit] append failed:', error instanceof Error ? error.message : 'unknown');
  }
}

/** Get recent recovery audit events (no secrets). */
export function getRecentRecoveryAudit(limit = 50): OwnerRecoveryAuditRecord[] {
  return recentEvents.slice(-limit);
}

/** Generate a cryptographically secure random recovery token. */
export function generateSecureRecoveryToken(): string {
  return randomBytes(32).toString('hex');
}

/** Count recent failed attempts per email in a time window. */
export function countRecentFailures(email: string, windowMs: number): number {
  const cutoff = Date.now() - windowMs;
  return recentEvents.filter(
    (e) => e.email === email && !e.success && new Date(e.timestamp).getTime() > cutoff,
  ).length;
}

/** Count recent SMS requests per email in a time window. */
export function countRecentRequests(email: string, windowMs: number): number {
  const cutoff = Date.now() - windowMs;
  return recentEvents.filter(
    (e) => e.email === email && e.action === 'request' && new Date(e.timestamp).getTime() > cutoff,
  ).length;
}
"}{"filePath": "expo/app/owner-sms-recovery.tsx", "content": "import React, { useState, useCallback, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TextInput,
  TouchableOpacity,
  Alert,
  ActivityIndicator,
  KeyboardAvoidingView,
  Platform,
  ScrollView,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useRouter, useLocalSearchParams } from 'expo-router';
import { ArrowLeft, Shield, Smartphone, KeyRound, Lock } from 'lucide-react-native';
import Colors from '@/constants/colors';
import { useAuth } from '@/lib/auth-context';
import { validateEmail, sanitizeEmail } from '@/lib/auth-helpers';
import {
  fetchOwnerRecoverySmsStatus,
  requestOwnerRecoverySms,
  verifyOwnerRecoverySms,
  type OwnerRecoveryStatus,
} from '@/lib/owner-recovery-sms';
import { IVX_LOGO_SOURCE } from '@/constants/brand';
import { Image } from 'react-native';

export default function OwnerSmsRecoveryScreen() {
  const router = useRouter();
  const params = useLocalSearchParams<{ email?: string }>();
  const { login } = useAuth();

  const [email, setEmail] = useState<string>(typeof params.email === 'string' ? params.email : '');
  const [code, setCode] = useState<string>('');
  const [newPassword, setNewPassword] = useState<string>('');
  const [confirmPassword, setConfirmPassword] = useState<string>('');
  const [step, setStep] = useState<'request' | 'verify' | 'reset' | 'done'>('request');
  const [loading, setLoading] = useState<boolean>(false);
  const [status, setStatus] = useState<OwnerRecoveryStatus | null>(null);
  const [phoneMasked, setPhoneMasked] = useState<string | null>(null);
  const [recoveryToken, setRecoveryToken] = useState<string | null>(null);

  useEffect(() => {
    fetchOwnerRecoverySmsStatus()
      .then(setStatus)
      .catch(() => setStatus({ ok: false, ready: false, transport: 'aws_sns', twilioPending: true, snsConfigured: false, awsCredentialsConfigured: false, awsRegion: 'us-east-1', recoveryPhoneConfigured: false, ownerEmailAllowlistConfigured: false }));
  }, []);

  const handleRequestCode = useCallback(async () => {
    const normalized = sanitizeEmail(email);
    if (!validateEmail(normalized)) {
      Alert.alert('Invalid email', 'Enter the owner email address.');
      return;
    }
    setLoading(true);
    try {
      const result = await requestOwnerRecoverySms(normalized);
      if (result.ok) {
        setPhoneMasked(result.phoneMasked);
        setStep('verify');
      } else {
        Alert.alert('Recovery SMS failed', result.message);
      }
    } finally {
      setLoading(false);
    }
  }, [email]);

  const handleVerifyCode = useCallback(async () => {
    const normalized = sanitizeEmail(email);
    if (!/^\d{6}$/.test(code)) {
      Alert.alert('Invalid code', 'Enter the 6-digit code from the SMS.');
      return;
    }
    setLoading(true);
    try {
      const result = await verifyOwnerRecoverySms(normalized, code);
      if (result.ok) {
        setRecoveryToken(result.recoveryToken ?? null);
        setStep('reset');
      } else {
        Alert.alert('Code verification failed', result.message);
      }
    } finally {
      setLoading(false);
    }
  }, [email, code]);

  const handleResetPassword = useCallback(async () => {
    const normalized = sanitizeEmail(email);
    if (newPassword.length < 8 || !/[A-Z]/.test(newPassword) || !/[0-9]/.test(newPassword)) {
      Alert.alert('Weak password', 'Password must be at least 8 characters with 1 uppercase letter and 1 number.');
      return;
    }
    if (newPassword !== confirmPassword) {
      Alert.alert('Password mismatch', 'The two passwords do not match.');
      return;
    }
    setLoading(true);
    try {
      const result = await verifyOwnerRecoverySms(normalized, code, newPassword);
      if (result.ok && result.passwordRepaired) {
        setStep('done');
        // Wait briefly, then sign in with the new password.
        setTimeout(() => {
          void login(normalized, newPassword).then((loginResult) => {
            if (loginResult.success) {
              router.replace('/(tabs)/(home)/home' as any);
            } else {
              Alert.alert('Auto sign-in failed', `${loginResult.message}\n\nPlease return to the login screen and sign in manually with the new password.`);
            }
          });
        }, 1500);
      } else {
        Alert.alert('Password reset failed', result.message);
      }
    } finally {
      setLoading(false);
    }
  }, [email, code, newPassword, confirmPassword, login, router]);

  const missingEnv = status && !status.ready;

  return (
    <View style={styles.root}>
      <SafeAreaView edges={['top', 'bottom']} style={{ flex: 1 }}>
        <KeyboardAvoidingView
          style={{ flex: 1 }}
          behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        >
          <ScrollView
            contentContainerStyle={styles.scrollContent}
            showsVerticalScrollIndicator={false}
            keyboardShouldPersistTaps="handled"
          >
            <TouchableOpacity style={styles.backButton} onPress={() => router.back()}>
              <ArrowLeft size={22} color={Colors.text} />
            </TouchableOpacity>

            <View style={styles.heroSection}>
              <View style={styles.logoCard}>
                <Image source={IVX_LOGO_SOURCE} style={styles.logo} resizeMode="contain" />
              </View>
              <Text style={styles.brand}>IVX HOLDINGS LLC</Text>
              <Text style={styles.tagline}>Owner SMS Recovery</Text>
            </View>

            <View style={styles.formCard}>
              <View style={styles.headerRow}>
                <Shield size={20} color={Colors.primary} />
                <Text style={styles.title}>Emergency owner recovery</Text>
              </View>
              <Text style={styles.subtitle}>
                A one-time recovery code is sent to the registered owner phone. The code expires in 5 minutes and can be used once.
              </Text>

              {missingEnv ? (
                <View style={styles.warningCard}>
                  <Text style={styles.warningTitle}>SMS provider not configured</Text>
                  <Text style={styles.warningText}>
